const rows = $input.all();
if (!rows.length) {
  return [{ json: { lines: '— немає витрат за останні 7 днів', total: '0.00', rowCount: 0, empty: true } }];
}
const lines = rows.map(r =>
  `  ${r.json.category}: ₴${r.json.total_uah} (${r.json.tx_count} tx)`
).join('\n');
const total = rows.reduce((s, r) => s + parseFloat(r.json.total_uah), 0);
return [{ json: { lines, total: total.toFixed(2), rowCount: rows.length, empty: false } }];

