// Parse Anthropic response. Fall back to raw spending lines if AI errors.
const body = $input.first()?.json ?? {};
const spending = $('Format spending data').first()?.json ?? {};
const aiText = body?.content?.[0]?.text;
if (aiText) {
  return [{ json: { text: aiText, errorMsg: '' } }];
}
const errorMsg = body?.error?.message || body?.error?.type || body?.type || '';
const fallback = spending.empty
  ? '— немає витрат за останні 7 днів'
  : `Витрати за тиждень (₴${spending.total}):\n${spending.lines}`;
return [{ json: { text: fallback, errorMsg } }];

// ADR-0038, Wave 3 §3.2 — pre-Telegram step that:
//   1. Builds a stable `alertId` so n8n retries no-op via
//      ON CONFLICT DO NOTHING server-side.
//   2. Carries forward upstream `text` so summary + Telegram body
//      reuse the same source.
const item = $input.first()?.json ?? {};
const spending = $('Format spending data').first()?.json ?? {};
const alertId = `${$workflow.id || 'wf08'}:${$execution.id || 'unknown'}:weekly-digest`;
const summary = item.errorMsg
  ? `Weekly financial digest (AI fallback) — ${item.errorMsg}`
  : `Weekly financial digest — ₴${spending.total || '0.00'} across ${spending.rowCount || 0} categories.`;
return [{
  json: {
    alertId,
    summary,
    text: item.text,
    errorMsg: item.errorMsg,
    metadata: {
      workflowId: $workflow.id || 'unknown',
      executionId: $execution.id || 'unknown',
      total: spending.total ?? null,
      rowCount: Number(spending.rowCount) || 0,
      aiFailed: Boolean(item.errorMsg),
    },
  },
}];

